// n8n에서 환경변수는 $env 로 접근
const secret = $env.N8N_WEBHOOK_SECRET || '';

// webhook typeVersion1: 헤더는 items[0].json.headers 에 위치
const allData = items[0].json;
const header = (allData.headers && allData.headers['x-scamanager-signature-256']) || '';

if (!secret || !header) {
  console.warn('HMAC soft-pass: secret=' + !!secret + ' header=' + !!header);
  return items;
}

// body는 파싱된 객체 — 재직렬화 후 HMAC 비교
const body = allData.body || {};
const rawBody = JSON.stringify(body);

const crypto = require('crypto');
const expected = 'sha256=' + crypto.createHmac('sha256', secret)
  .update(rawBody, 'utf8').digest('hex');

const hBuf = Buffer.from(header);
const eBuf = Buffer.from(expected);
if (hBuf.length !== eBuf.length || !crypto.timingSafeEqual(hBuf, eBuf)) {
  // 테스트 단계: soft fail — 운영 전 throw 로 변경
  console.warn('HMAC mismatch — soft pass for testing');
}

return items;

const key = items[0].json.work_key;
const store = $getWorkflowStaticData('node');
const TTL_MS = 20 * 60 * 1000;

if (store[key] && Date.now() - store[key] < TTL_MS) {
  return [];
}

store[key] = Date.now();
return items;

const { execFileSync } = require('child_process');

const item = items[0].json;
const env = Object.assign({}, $env, {
  REPO:              String(item.repo || ''),
  ISSUE_NUMBER:      String(item.issue_number || ''),
  ISSUE_TITLE:       String(item.issue_title || ''),
  ISSUE_BODY:        String(item.issue_body || ''),
  GH_TOKEN:          String(item.repo_token || ''),
  ANTHROPIC_API_KEY: $env.ANTHROPIC_API_KEY || '',
});

let exitCode = 0;
let stdout = '';
let stderr = '';

try {
  stdout = execFileSync('/opt/claude-runner/claude_fix.sh', [], {
    env,
    timeout: 960000,
    maxBuffer: 1024 * 1024 * 10,
  }).toString();
} catch (e) {
  exitCode = typeof e.status === 'number' ? e.status : 1;
  stdout = e.stdout ? e.stdout.toString() : '';
  stderr = e.stderr ? e.stderr.toString().slice(0, 2000) : '';
}

return [{ json: { exitCode, stdout, stderr } }];
